#@title 5) Audio loading + preprocessing

def load_audio(path, sr=16000):
    """Load mono audio, resample to sr."""
    y, sr_out = librosa.load(path, sr=sr, mono=True)
    y = np.nan_to_num(y).astype(np.float32)
    return y, sr_out

def preprocess_audio(y, sr, target_duration=5.0):
    """Basic preprocessing.

    🟨 STUDENT TODO: Improve this function.
    Ideas:
      - peak or RMS normalization
      - trim leading/trailing silence
      - fixed-length padding/truncation (e.g., 5s)
      - pre-emphasis filter
    """

    # 1. Trim silence
    y, _ = librosa.effects.trim(y, top_db=30)

    # 2. Pre-emphasis filter
    pre_emphasis = 0.97
    y = np.append(y[0], y[1:] - pre_emphasis * y[:-1])

    # 3. Fixed-length padding / truncation
    target_len = int(target_duration * sr)
    if len(y) < target_len:
        y = np.pad(y, (0, target_len - len(y)), mode='constant')
    else:
        y = y[:target_len]

    # 4. RMS normalization (more robust to noise than peak normalization)
    rms = np.sqrt(np.mean(y ** 2))
    if rms > 0:
        y = y / rms
    else:
        y = np.zeros(int(target_duration * sr), dtype=np.float32)

    return y

#@title 6) Feature extraction (baseline: MFCC stats)

def features_mfcc_stats(y, sr, n_mfcc=20, n_fft=1024, hop=256):
    mfcc = librosa.feature.mfcc(y=y, sr=sr, n_mfcc=n_mfcc, n_fft=n_fft, hop_length=hop)
    d1 = librosa.feature.delta(mfcc)
    d2 = librosa.feature.delta(mfcc, order=2)

    def stats(M):
        return np.concatenate([M.mean(axis=1), M.std(axis=1)], axis=0)

    return np.concatenate([stats(mfcc), stats(d1), stats(d2)], axis=0).astype(np.float32)

def extract_features(path, sr=16000):
    """Return a 1D feature vector for one clip.

    🟨 STUDENT TODO: Improve feature extraction here.
    Options:
      - log-mel spectrogram stats
      - spectral centroid/bandwidth/rolloff/flux
      - CMVN on MFCC/log-mel
      - multi-window features
      - robust pooling (median, percentiles)
    """
    y, sr = load_audio(path, sr=sr)
    y = preprocess_audio(y, sr)

    if TRAINING_MODE:
      y = augment_waveform(y, sr, prob=0.5)

    features = []

    # 1️⃣ Baseline MFCC stats (already given)
    mfcc_feat = features_mfcc_stats(y, sr)
    features.append(mfcc_feat)

    # 2️⃣ Log-Mel Spectrogram + CMVN
    mel = librosa.feature.melspectrogram(y=y, sr=sr, n_fft=1024, hop_length=256, n_mels=64)
    log_mel = librosa.power_to_db(mel)
    log_mel = (log_mel - log_mel.mean(axis=1, keepdims=True)) / \
              (log_mel.std(axis=1, keepdims=True) + 1e-6)
    mel_stats = np.concatenate([
        log_mel.mean(axis=1),
        log_mel.std(axis=1),
        np.median(log_mel, axis=1),
        np.percentile(log_mel, 25, axis=1),
        np.percentile(log_mel, 75, axis=1)
    ])
    features.append(mel_stats)

    # 3️⃣ Spectral Features
    centroid = librosa.feature.spectral_centroid(y=y, sr=sr)
    bandwidth = librosa.feature.spectral_bandwidth(y=y, sr=sr)
    rolloff   = librosa.feature.spectral_rolloff(y=y, sr=sr)
    flux      = librosa.onset.onset_strength(y=y, sr=sr)

    def stat_feat(x):
        return np.array([x.mean(), x.std(), np.median(x),
                         np.percentile(x, 25), np.percentile(x, 75)])

    spectral_feat = np.concatenate([
        stat_feat(centroid), stat_feat(bandwidth),
        stat_feat(rolloff),  stat_feat(flux)
    ])
    features.append(spectral_feat)

    # 4️⃣ Delta and delta-delta on log-mel
    log_mel_delta  = librosa.feature.delta(log_mel)
    log_mel_delta2 = librosa.feature.delta(log_mel, order=2)
    for dm in [log_mel_delta, log_mel_delta2]:
        features.append(np.concatenate([dm.mean(axis=1), dm.std(axis=1)]))

    # 5️⃣ Zero-crossing rate
    zcr = librosa.feature.zero_crossing_rate(y)
    features.append(stat_feat(zcr))

    return np.concatenate(features).astype(np.float32)

