# Noise implementation

import random
from scipy.signal import butter, sosfilt

def augment_waveform(y, sr, prob=0.5):
    """
    Randomly apply one or more of:
      1. Additive white Gaussian noise
      2. Random gain  (±6 dB)
      3. Random bandpass filter
      4. Circular time shift  (±0.2 s)
    Each is applied independently with probability `prob`.
    """
    # 1. Additive white Gaussian noise
    if random.random() < prob:
        noise_level = random.uniform(0.001, 0.015)
        y = y + noise_level * np.random.randn(len(y)).astype(np.float32)

    # 2. Random gain ±6 dB
    if random.random() < prob:
        gain_db = random.uniform(-6, 6)
        y = y * (10 ** (gain_db / 20.0))

    # 3. Random bandpass filter
    if random.random() < prob:
        low_n  = np.clip(random.uniform(200,  1000) / (sr / 2), 1e-4, 0.9999)
        high_n = np.clip(random.uniform(4000, 7000) / (sr / 2), 1e-4, 0.9999)
        if low_n < high_n:
            sos = butter(4, [low_n, high_n], btype='band', output='sos')
            y   = sosfilt(sos, y).astype(np.float32)

    # 4. Circular time shift ±0.2 s
    if random.random() < prob:
        shift = random.randint(-int(0.2 * sr), int(0.2 * sr))
        y = np.roll(y, shift)

    # Re-normalize after augmentation
    peak = np.max(np.abs(y))
    if peak > 0:
        y = y / peak

    return y

